1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	}
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	
27	function countByType(items: QuoteItem[]): Map<string, number> {
28	  const counts = new Map<string, number>();
29	  for (const item of items) {
30	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	  }
32	  return counts;
33	}
34	
35	function priceGroup(type: string, count: number): number {
36	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
37	}
38	
39	export function quote(input: QuoteInput): number {
40	  const countsByType = countByType(input.items);
41	
42	  let basePremium = 0;
43	  for (const [type, count] of countsByType) {
44	    basePremium += priceGroup(type, count);
45	  }
46	
47	  return basePremium + PROCESSING_FEE;
48	}
49	
50	export function claim(input: unknown): number {
51	  return undefined as unknown as number;
52	}
